    },
    {
      "id": "a2",
      "assumption": "The @/ path alias resolves correctly in tests (vitest.config.ts already configures this).",
      "confidence": 0.99,
      "if_wrong": "Would need relative imports instead of alias imports."
    },
    {
      "id": "a3",
      "assumption": "No mocking is needed — all six functions are pure utility functions with no external dependencies.",
      "confidence": 0.99,
      "if_wrong": "Would need to set up mocks, significantly changing the test structure."
    },
