      "id": "a4",
      "assumption": "URLSearchParams is available in the jsdom test environment without polyfills.",
      "confidence": 0.98,
      "if_wrong": "Would need to add a URLSearchParams polyfill to the test setup."
    },
    {
      "id": "a5",
      "assumption": "The valid MarketStatus values are 'active', 'resolved', 'closed', 'draft' and valid MarketListSort values are 'volume', 'liquidity', 'created' — these are the exhaustive sets to test against.",
